index c06d5c759634..654068437564 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -3009,6 +3009,52 @@ static Value *foldAndOrOfICmpEqZeroAndICmp(ICmpInst *LHS, ICmpInst *RHS,
       Other);
 }

+// (icmp eq X, -1) | (icmp ugt X+1, Y) -> (icmp uge X, Y)
+// (icmp ne X, -1) & (icmp ule X+1, Y) -> (icmp ult X, Y)
+static Value *foldAndOrOfICmpEqAllOnesAndICmp(ICmpInst *LHS, ICmpInst *RHS,
+                                              bool IsAnd, bool IsLogical,
+                                              IRBuilderBase &Builder) {
+  ICmpInst::Predicate LPred =
+      IsAnd ? LHS->getInversePredicate() : LHS->getPredicate();
+  ICmpInst::Predicate RPred =
+      IsAnd ? RHS->getInversePredicate() : RHS->getPredicate();
+  Value *LHS0 = LHS->getOperand(0);
+  if (LPred != ICmpInst::ICMP_EQ || !match(LHS->getOperand(1), m_AllOnes()) ||
+      !LHS0->getType()->isIntOrIntVectorTy() ||
+      !(LHS->hasOneUse() || RHS->hasOneUse()))
+    return nullptr;
+
+  Value *Y = nullptr;
+  // Check if one operand of RHS is (LHS0 + something)
+  for (unsigned i = 0; i < 2; ++i) {
+    Value *Op = RHS->getOperand(i);
+    // Directly check if Op is defined by an Add instruction
+    if (auto *Add = dyn_cast<BinaryOperator>(Op)) {
+      if (Add->getOpcode() == Instruction::Add) {
+        if (Add->getOperand(0) == LHS0) {
+          Y = Add->getOperand(1);
+          break;
+        }
+        if (Add->getOperand(1) == LHS0) {
+          Y = Add->getOperand(0);
+          break;
+        }
+      }
+    }
+  }
+  if (!Y)
+    return nullptr;
+
+  // For AND, the inverted predicate should be ugt (from original ule)
+  if (RPred != ICmpInst::ICMP_UGT)
+    return nullptr;
+
+  if (IsLogical)
+    Y = Builder.CreateFreeze(Y);
+  return Builder.CreateICmp(
+      IsAnd ? ICmpInst::ICMP_ULT : ICmpInst::ICMP_UGE, LHS0, Y);
+}
+
 /// Fold (icmp)&(icmp) or (icmp)|(icmp) if possible.
 /// If IsLogical is true, then the and/or is in select form and the transform
 /// must be poison-safe.

